class Node:
    def __init__(self, key):
        self.left = None
        self.right = None
        self.val = key

# Insert a node into BST
def insert(root, key):
    if root is None:
        return Node(key)
    if key < root.val:
        root.left = insert(root.left, key)
    else:
        root.right = insert(root.right, key)
    return root

# Inorder traversal (left, root, right) - yields sorted elements
def inorder(root, res):
    if root:
        inorder(root.left, res)
        res.append(root.val)
        inorder(root.right, res)

# Construct and traverse a BST
root_node = Node(50)
insert(root_node, 30)
insert(root_node, 70)
insert(root_node, 20)

sorted_elements = []
inorder(root_node, sorted_elements)
print(sorted_elements) # [20, 30, 50, 70]
